const items = $input.all();

function cleanString(value) {
  if (value == null) return '';
  const text = String(value).replace(/\s+/g, ' ').trim();
  return text || '';
}

function cleanMultiline(value) {
  if (value == null) return '';
  const text = String(value)
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  return text || '';
}

function cleanNumber(value) {
  if (value == null || value === '') return '';
  if (typeof value === 'number') {
    return Number.isFinite(value) ? value : '';
  }
  let text = String(value)
    .replace(/\u00a0/g, ' ')
    .replace(/\u20ac/g, '')
    .replace(/\b(EUR|EURO|m\u00b2|m2|qm|%|Stk\.?|St\.?|p\.a\.|pa)\b/gi, '')
    .replace(/--/g, '')
    .replace(/,-/g, '')
    .replace(/[^0-9,.-]/g, '');
  if (!text || text === '-' || text === '--') return '';
  if (text.includes(',') && text.includes('.')) {
    text = text.replace(/\./g, '').replace(',', '.');
  } else if (text.includes(',')) {
    text = text.replace(',', '.');
  } else {
    text = text.replace(/(\d)\.(?=\d{3}(\D|$))/g, '$1');
  }
  const parsed = Number(text);
  return Number.isFinite(parsed) ? parsed : '';
}

function stringifyValue(value) {
  if (value == null || value === '') return '';
  if (typeof value === 'string') return cleanMultiline(value);
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) return value.map(stringifyValue).filter(Boolean).join('\n');
  if (typeof value === 'object') return Object.values(value).map(stringifyValue).filter(Boolean).join('\n');
  return cleanMultiline(value);
}

function buildProviderContactString(value) {
  if (!value) return '';
  if (typeof value === 'string') return cleanMultiline(value);
  const parts = [];
  if (value.name) parts.push(cleanString(value.name));
  if (value.company && cleanString(value.company) !== cleanString(value.name)) parts.push(cleanString(value.company));
  if (value.phone) parts.push(cleanString(value.phone));
  if (value.email) parts.push(cleanString(value.email));
  return parts.filter(Boolean).join('\n');
}

function deriveProjectName(source) {
  const explicit = cleanString(source.Project_name || source.project_name);
  if (explicit) return explicit;
  const sourceAddress = buildMergedAddress(source);
  return cleanString(sourceAddress['Stra\u00dfe'] || sourceAddress.street);
}

function pickFirstNonEmpty(values) {
  for (const candidate of values) {
    const value = cleanString(candidate);
    if (value) return value;
  }
  return '';
}

function buildMergedAddress(source) {
  const rimAddress = source.Adresse && typeof source.Adresse === 'object' ? source.Adresse : {};
  const canonicalAddress = source.address && typeof source.address === 'object' ? source.address : {};
  return {
    Land: pickFirstNonEmpty([rimAddress.Land, canonicalAddress.country]),
    Bundesland: pickFirstNonEmpty([rimAddress.Bundesland, canonicalAddress.state]),
    PLZ: pickFirstNonEmpty([rimAddress.PLZ, canonicalAddress.postal_code]),
    Stadt: pickFirstNonEmpty([rimAddress.Stadt, canonicalAddress.city]),
    Stra\u00dfe: pickFirstNonEmpty([rimAddress['Stra\u00dfe'], canonicalAddress.street]),
    Hausnummer: pickFirstNonEmpty([rimAddress.Hausnummer, canonicalAddress.house_number]),
    country: pickFirstNonEmpty([canonicalAddress.country, rimAddress.Land]),
    state: pickFirstNonEmpty([canonicalAddress.state, rimAddress.Bundesland]),
    postal_code: pickFirstNonEmpty([canonicalAddress.postal_code, rimAddress.PLZ]),
    city: pickFirstNonEmpty([canonicalAddress.city, rimAddress.Stadt]),
    street: pickFirstNonEmpty([canonicalAddress.street, rimAddress['Stra\u00dfe']]),
    house_number: pickFirstNonEmpty([canonicalAddress.house_number, rimAddress.Hausnummer]),
  };
}

function normalizeCountry(value) {
  const cleaned = cleanString(value);
  if (!cleaned) return '\u00d6sterreich';
  if (/^austria$/i.test(cleaned) || /^\u00f6sterreich$/i.test(cleaned)) return '\u00d6sterreich';
  return cleaned;
}

function deriveBundesland(address) {
  const existing = cleanString(address['Bundesland'] || address.state);
  if (existing) return existing;
  const city = cleanString(address.Stadt || address.city).toLowerCase();
  const postalCode = cleanString(address.PLZ || address.postal_code);
  const cityMap = {
    'wien': 'Wien',
    'graz': 'Steiermark',
    'salzburg': 'Salzburg',
    'linz': 'Ober\u00f6sterreich',
    'innsbruck': 'Tirol',
    'klagenfurt': 'K\u00e4rnten',
    'villach': 'K\u00e4rnten',
    'st. p\u00f6lten': 'Nieder\u00f6sterreich',
    'st p\u00f6lten': 'Nieder\u00f6sterreich',
    'wels': 'Ober\u00f6sterreich',
    'eisenstadt': 'Burgenland',
    'bregenz': 'Vorarlberg',
  };
  if (cityMap[city]) return cityMap[city];
  if (/^1\d{3}$/.test(postalCode)) return 'Wien';
  if (/^(2|3)\d{3}$/.test(postalCode) || postalCode === '3100') return 'Nieder\u00f6sterreich';
  if (/^4\d{3}$/.test(postalCode)) return 'Ober\u00f6sterreich';
  if (/^5\d{3}$/.test(postalCode)) return 'Salzburg';
  if (/^7\d{3}$/.test(postalCode)) return 'Burgenland';
  if (/^8\d{3}$/.test(postalCode)) return 'Steiermark';
  if (/^9\d{3}$/.test(postalCode)) return 'K\u00e4rnten';
  return '';
}

function mapAssetClass(source) {
  const existing = cleanString(source.Assetklasse);
  if (existing) return existing;
  const joined = [
    source.asset_class,
    source.property && source.property.property_type,
    source.property && source.property.planned_use,
    source.property && source.property.object_category,
    source.notes,
  ].map(cleanString).filter(Boolean).join(' ').toLowerCase();

  if (!joined) return '';
  if (/universit|hochschule|campus/.test(joined)) return 'Universit\u00e4t';
  if (/schule|kindergarten/.test(joined)) return 'Schule';
  if (/sicherheit|polizei|feuerwehr|kaserne|gericht/.test(joined)) return 'Sicherheit';
  if (/wohnen|wohn|residential|apartment|mehrfamilien|wohnung/.test(joined)) {
    return 'Wohnen';
  }
  if (/b\u00fcro|office/.test(joined)) return 'B\u00fcro';
  return '';
}

function findAnnualValue(text, label) {
  if (!text) return '';
  const lines = String(text).split('\n');
  for (const line of lines) {
    if (!new RegExp(label, 'i').test(line) || !/p\.a\.|pa/i.test(line)) continue;
    const matches = line.match(/[\d.,]+/g) || [];
    if (!matches.length) continue;
    const candidate = cleanNumber(matches[0]);
    if (candidate !== '') return candidate;
  }
  return '';
}

function mapToRim(source, runtime) {
  const sourceAddress = buildMergedAddress(source);
  const sourceAdditional = source['Zus\u00e4tzliche_Informationen'] && typeof source['Zus\u00e4tzliche_Informationen'] === 'object'
    ? source['Zus\u00e4tzliche_Informationen']
    : {};
  const sourceLage = source.Lagebeschreibung && typeof source.Lagebeschreibung === 'object' ? source.Lagebeschreibung : {};
  const sourceInfra = sourceLage.Mikrolage_und_Infrastruktur && typeof sourceLage.Mikrolage_und_Infrastruktur === 'object'
    ? sourceLage.Mikrolage_und_Infrastruktur
    : {};
  const sourceTraffic = sourceLage.Verkehrsanbindung && typeof sourceLage.Verkehrsanbindung === 'object'
    ? sourceLage.Verkehrsanbindung
    : {};
  const sourceDistances = sourceLage.Entfernungen && typeof sourceLage.Entfernungen === 'object'
    ? sourceLage.Entfernungen
    : {};
  const annualSoll = findAnnualValue(runtime.extracted_text, 'SOLL');
  const annualIst = findAnnualValue(runtime.extracted_text, 'IST');

  return {
    Project_name: deriveProjectName(source),
    Anbieter: cleanString(source.Anbieter || source.provider),
    Kontaktdaten_Anbieter: buildProviderContactString(source.Kontaktdaten_Anbieter || source.provider_contact),
    Eigent\u00fcmer: cleanString(source['Eigent\u00fcmer'] || source.owner),
    Adresse: {
      Land: normalizeCountry(sourceAddress.Land || sourceAddress.country),
      Bundesland: deriveBundesland(sourceAddress),
      PLZ: cleanString(sourceAddress.PLZ || sourceAddress.postal_code),
      Stadt: cleanString(sourceAddress.Stadt || sourceAddress.city),
      Stra\u00dfe: cleanString(sourceAddress['Stra\u00dfe'] || sourceAddress.street),
      Hausnummer: cleanString(sourceAddress.Hausnummer || sourceAddress.house_number),
    },
    Assetklasse: mapAssetClass(source),
    'Nutzfl\u00e4che_m2': cleanNumber(source['Nutzfl\u00e4che_m2'] != null ? source['Nutzfl\u00e4che_m2'] : source.areas && source.areas.usable_area_m2),
    'Grundst\u00fccksfl\u00e4che_m2': cleanNumber(source['Grundst\u00fccksfl\u00e4che_m2'] != null ? source['Grundst\u00fccksfl\u00e4che_m2'] : source.areas && source.areas.plot_area_m2),
    SOLL_Mieteinnahme_EUR_p_a: annualSoll !== '' ? annualSoll : cleanNumber(source.SOLL_Mieteinnahme_EUR_p_a),
    IST_Mieteinnahme_EUR_p_a: annualIst !== '' ? annualIst : cleanNumber(source.IST_Mieteinnahme_EUR_p_a),
    Kaufpreisvorstellung_EUR: cleanNumber(source.Kaufpreisvorstellung_EUR != null ? source.Kaufpreisvorstellung_EUR : source.financials && source.financials.asking_price_eur),
    'Kaufpreis_pro_m2_Nutzfl\u00e4che_EUR': cleanNumber(source['Kaufpreis_pro_m2_Nutzfl\u00e4che_EUR'] != null ? source['Kaufpreis_pro_m2_Nutzfl\u00e4che_EUR'] : source.financials && source.financials.price_per_m2_usable_area),
    'Kaufpreis_pro_m2_Grundst\u00fcck_EUR': cleanNumber(source['Kaufpreis_pro_m2_Grundst\u00fcck_EUR'] != null ? source['Kaufpreis_pro_m2_Grundst\u00fcck_EUR'] : source.financials && source.financials.price_per_m2_land),
    Objekttyp: cleanString(source.Objekttyp || source.property && (source.property.object_category || source.property.property_type)),
    Eigentumsform: cleanString(source.Eigentumsform || source.property && source.property.ownership_type),
    Bruttoanfangsrendite_IST: cleanNumber(source.Bruttoanfangsrendite_IST != null ? source.Bruttoanfangsrendite_IST : source.returns && source.returns.gross_initial_yield_actual),
    Bruttoanfangsrendite_SOLL: cleanNumber(source.Bruttoanfangsrendite_SOLL != null ? source.Bruttoanfangsrendite_SOLL : source.returns && source.returns.gross_initial_yield_target),
    'Zus\u00e4tzliche_Informationen': {
      Baujahr: cleanNumber(sourceAdditional.Baujahr != null ? sourceAdditional.Baujahr : source.property && source.property.construction_year),
      Maklerprovision: cleanString(sourceAdditional.Maklerprovision != null ? sourceAdditional.Maklerprovision : source.financials && source.financials.broker_commission),
      Denkmalschutz: stringifyValue(sourceAdditional.Denkmalschutz != null ? sourceAdditional.Denkmalschutz : source.property && source.property.heritage_protection),
      Leerstand: cleanNumber(sourceAdditional.Leerstand != null ? sourceAdditional.Leerstand : source.property && source.property.vacancy),
      'Stellpl\u00e4tze': cleanNumber(sourceAdditional['Stellpl\u00e4tze'] != null ? sourceAdditional['Stellpl\u00e4tze'] : source.property && source.property.parking_spaces),
    },
    Lagebeschreibung: {
      Makrolage: cleanMultiline(sourceLage.Makrolage || ''),
      Mikrolage_und_Infrastruktur: {
        Bildungsbauten: cleanString(sourceInfra.Bildungsbauten),
        Medizinische_Versorgung: cleanString(sourceInfra.Medizinische_Versorgung),
        'Einkaufsm\u00f6glichkeiten': cleanString(sourceInfra['Einkaufsm\u00f6glichkeiten']),
      },
      Umliegende_Bebauung: cleanString(sourceLage.Umliegende_Bebauung),
      Verkehrsanbindung: {
        Oeffentlicher_Verkehr: cleanString(sourceTraffic.Oeffentlicher_Verkehr),
        Individualverkehr: cleanString(sourceTraffic.Individualverkehr),
      },
      Entfernungen: {
        Naechster_Bahnhof: {
          Bezeichnung: cleanString(sourceDistances.Naechster_Bahnhof && sourceDistances.Naechster_Bahnhof.Bezeichnung),
          Entfernung: cleanString(sourceDistances.Naechster_Bahnhof && sourceDistances.Naechster_Bahnhof.Entfernung),
        },
        Ortsmitte: {
          Bezeichnung: cleanString(sourceDistances.Ortsmitte && sourceDistances.Ortsmitte.Bezeichnung),
          Entfernung: cleanString(sourceDistances.Ortsmitte && sourceDistances.Ortsmitte.Entfernung),
        },
        Flughafen: {
          Bezeichnung: cleanString(sourceDistances.Flughafen && sourceDistances.Flughafen.Bezeichnung),
          Entfernung: cleanString(sourceDistances.Flughafen && sourceDistances.Flughafen.Entfernung),
        },
      },
    },
  };
}

return items.map((item) => {
  const payload = JSON.parse(JSON.stringify(item.json || {}));
  const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};
  const processingMetadata =
    payload.processing_metadata && typeof payload.processing_metadata === 'object'
      ? payload.processing_metadata
      : {};

  return {
    json: {
      json_payload: mapToRim(payload, runtime),
      pdf_hash: processingMetadata.document_id ?? runtime.document_hash ?? null,
      pdf_data: runtime.pdf_base64 ?? null,
      pdf_filename: processingMetadata.source_filename ?? runtime.source_filename ?? null,
      pdf_mime_type: runtime.pdf_mime_type ?? 'application/pdf',
      pdf_size_bytes: runtime.pdf_size_bytes ?? null,
    },
  };
});

const items = $input.all();
const dbResult = items[0]?.json || {};

// Get the original payload passed into this sub-workflow
let originalPayload = {};
try {
  originalPayload = JSON.parse(JSON.stringify(($('Receive Structured Payload').first()?.json) || {}));
} catch (e) {
  originalPayload = {};
}

if (!originalPayload || typeof originalPayload !== 'object' || Array.isArray(originalPayload)) {
  originalPayload = {};
}

const runtime = originalPayload._runtime && typeof originalPayload._runtime === 'object' ? originalPayload._runtime : {};
const persistenceError =
  dbResult.error?.message ||
  dbResult.error?.description ||
  dbResult.message ||
  dbResult.error ||
  null;

originalPayload._runtime = {
  ...runtime,
  persistence_attempted: true,
  persistence_error: persistenceError,
};

return [{ json: originalPayload }];
